export const D4B = {
  7: {
    sessions: [
      { day: 'Mon Mar 16', title: 'Session 1 — Vocabulary: Value-Add, Going-In Cap, Stabilized Cap, Mark-to-Market' },
      { day: 'Wed Mar 18', title: 'Session 2 — Underwriting a Value-Add Business Plan: Buy → Improve → Lease → Exit' },
      { day: 'Thu Mar 19', title: 'Session 3 — Modeling Lease-Up Risk and Renovation Timeline in a DCF' },
      { day: 'Fri Mar 20', title: 'Session 4 — Value-Add vs. Core Returns Comparison + 20-Question Quiz' },
    ],
    vocabulary: [
      { term: 'Value-Add', full: 'Value-Add Investment Strategy', definition: 'An investment approach targeting properties with below-market rents, deferred maintenance, or near-term lease expirations where operational improvements can increase NOI and drive appreciation. Higher risk than core (execution and lease-up risk) but targets higher returns (15–20%+ IRR).', example: 'Acquire 80K SF Long Beach industrial at 4.5% going-in cap with below-market rents; renovate, re-lease at market, exit at 5.0% stabilized cap for 2.0×+ equity multiple.' },
      { term: 'Going-In Cap Rate', full: 'Going-In Capitalization Rate', definition: 'The cap rate at acquisition based on current (in-place) NOI. For value-add deals, the going-in cap is typically HIGHER than market cap rates — reflecting the property\'s current underperformance. Investors buy at a higher yield (lower price relative to stabilized income) to capture the upside.', example: 'Value-add acquisition: purchase $16M, current NOI $720K → going-in cap 4.5%; stabilized NOI $1.1M → implied stabilized cap 6.9% on cost = strong value creation.' },
      { term: 'Stabilized Cap Rate', full: 'Stabilized Capitalization Rate', definition: 'The cap rate based on fully stabilized NOI — after renovation, lease-up, and mark-to-market rent. Used to calculate the exit value at stabilization. The spread between going-in cap and stabilized cap (on cost) represents the value created by the value-add business plan.', example: 'Going-in cap on cost: 4.5%; stabilized cap on cost: 6.9% → 240 bps value-creation spread.' },
      { term: 'Mark-to-Market', full: 'Mark-to-Market Rent Increase', definition: 'The process of resetting below-market in-place rents to current market rates at lease renewal or new tenancy. The NOI uplift from marking rents to market is the core value-creation engine in most industrial value-add deals. Quantified as: (market rent − in-place rent) × rentable area.', example: 'In-place rent $1.40/SF/mo; market rent $1.90/SF/mo; 80,000 SF. Annual uplift = ($1.90 − $1.40) × 80,000 × 12 = $480,000/yr additional NOI.' },
      { term: 'Renovation Budget', full: 'Value-Add Renovation Budget', definition: 'Capital investment made to upgrade the property: roof replacement, parking lot, dock levelers, LED lighting, HVAC, paint, and landscaping. Improves lease-ability, supports higher rents, and extends building life. Typically $5–$20/SF for light industrial refresh; $20–$50/SF for substantial repositioning.', example: '$12/SF renovation budget on 80,000 SF = $960,000 capital investment. Projected NOI uplift from improved rents: $480,000/yr → payback in 2 years.' },
      { term: 'Lease-Up Period', full: 'Lease-Up Period', definition: 'The time required to find, negotiate, and execute new leases after renovation completion. Vacancy during lease-up means no income from affected space. A key risk in value-add underwriting: longer lease-up → lower IRR. Market conditions, property quality, and asking rent determine lease-up speed.', example: '80,000 SF value-add industrial; renovation 6 months; lease-up budget: 9 months to stabilization → total vacancy period 15 months from acquisition to first full-rent check.' },
    ],
    quiz: [
      { q: 'A value-add investment strategy targets:', opts: ['Fully leased, stabilized properties with no upside', 'Properties with below-market rents, deferred maintenance, or near-term expirations — where operational improvements drive NOI and appreciation', 'Ground-up development only', 'Government-leased buildings with long-term leases'], a: 1, exp: 'Value-add = buy a property with known "problems" that can be fixed. The NOI uplift from fixing those problems (re-leasing, renovating, managing better) creates value above the purchase price.' },
      { q: 'The "going-in cap" in a value-add deal is typically __ the stabilized cap rate:', opts: ['Lower than — you pay more per dollar of current income', 'Higher than — you buy at a discounted price relative to current (below-market) income', 'Equal to — the market prices in the upside', 'Irrelevant — only exit cap matters'], a: 1, exp: 'Value-add going-in cap > market cap rate because the property is currently underperforming. You\'re buying the upside potential at a discount. Once stabilized, the exit cap should be at or below current market caps.' },
      { q: 'Mark-to-market rent increase of $0.40/SF/mo on a 100,000 SF industrial building adds how much annual NOI?', opts: ['$40,000', '$400,000', '$480,000', '$4,000,000'], a: 2, exp: '$0.40/SF/mo × 100,000 SF × 12 months = $480,000/yr additional NOI. This is the annual value of the mark-to-market opportunity.' },
      { q: 'A value-add acquisition has in-place NOI of $800K and stabilized NOI of $1.2M. Purchase price is $16M. Going-in and stabilized yields on cost are:', opts: ['Going-in 5.0%, stabilized 7.5%', 'Going-in 4.0%, stabilized 7.5%', 'Going-in 5.0%, stabilized 6.0%', 'Going-in 6.0%, stabilized 7.5%'], a: 0, exp: 'Going-in: $800K ÷ $16M = 5.0%. Stabilized: $1,200K ÷ $16M = 7.5%. The 250 bps spread (5.0% to 7.5%) represents significant value creation potential.' },
      { q: 'Lease-up risk in a value-add deal refers to:', opts: ['The risk that the renovation costs more than budgeted', 'The risk that the property takes longer than underwritten to re-lease after renovation, extending the vacancy period and reducing IRR', 'The risk of tenant default during the hold', 'Interest rate risk on the bridge loan'], a: 1, exp: 'Lease-up risk: every month of vacancy above the underwritten timeline is lost income. A 6-month longer lease-up on an 80K SF building at $1.90/SF/mo = $912,000 in lost revenue and a materially lower IRR.' },
      { q: 'A value-add industrial deal acquires a building at $180/SF with $15/SF renovation budget. All-in cost: $195/SF. Stabilized market cap is 5.0%. To justify the investment (minimum 100 bps spread), stabilized NOI per SF must be at least:', opts: ['$9.75/SF/yr', '$10.725/SF/yr', '$11.70/SF/yr', '$9.00/SF/yr'], a: 1, exp: 'YOC target = 5.0% + 1.0% (min spread) = 6.0% minimum. Required NOI = $195/SF × 6.0% = $11.70/SF/yr. Monthly NNN rent equivalent: $11.70 ÷ 12 = $0.975/SF/mo.' },
      { q: 'A value-add deal assumes lease-up of 12 months at 50% occupancy, then 95% thereafter. Month 13 to Year 10 at full market rent. This creates what cash flow pattern?', opts: ['Flat annual cash flow from Day 1', 'Low/negative cash flow in months 1–12 (renovation + partial occupancy), then strong stabilized cash flow — a "J-curve" return profile', 'High cash flow initially then declining', 'No meaningful difference from a core acquisition'], a: 1, exp: 'Value-add typically shows a J-curve: early negative or low returns during renovation and lease-up, followed by strong stabilized returns once the business plan executes. IRR is sensitive to how quickly the curve inflects.' },
      { q: 'A 9-month lease-up vs. a 15-month lease-up (all else equal) impacts IRR by:', opts: ['Less than 50 basis points — lease-up has minimal IRR impact', 'Potentially 200–400 bps — the additional 6 months of vacancy on an 80K SF building at $1.90/SF/mo is $912K in lost NOI, directly reducing returns', 'Exactly 1.0% IRR reduction per month', 'No impact if the asset has a bridge loan'], a: 1, exp: 'Lost income during extended lease-up directly reduces IRR. An extra 6 months of vacancy on a substantial building can reduce IRR by several hundred basis points — making lease-up assumptions one of the most important (and most optimistic) inputs to scrutinize.' },
      { q: 'A value-add renovation budget of $15/SF on a 100K SF building is $1.5M. If this renovation enables a $0.25/SF/mo rent increase (NNN), the annual return on the renovation capex is:', opts: ['10%', '20%', '25%', '40%'], a: 1, exp: '$0.25/SF/mo × 100K SF × 12 = $300K annual NOI uplift ÷ $1.5M renovation = 20% return on capex. A 20% levered return on renovation capital is attractive.' },
      { q: 'What is the primary exit strategy for a value-add industrial investment after stabilization?', opts: ['Convert to multifamily', 'Sell at market cap rate applied to stabilized NOI — capturing value created through rent growth and renovation', 'Refinance and hold forever', 'Convert to owner-occupied and sell to an end user'], a: 1, exp: 'Standard value-add exit: stabilize → sell at market cap rate applied to new (higher) stabilized NOI. The exit value = (stabilized NOI) ÷ (market cap rate) — you\'re selling the building as a "core" investment to a buyer who wants stabilized income.' },
      { q: 'In-place lease expires in 8 months. Market asking rent is $1.95/SF/mo; in-place rent is $1.55/SF/mo. Acquisition price is $20M. The value-add thesis here is:', opts: ['Hold the tenant at $1.55/SF/mo to preserve occupancy', 'At lease expiration, renew at $1.95/SF/mo or re-lease at market — capturing $480K annual NOI uplift on 100K SF, creating ~$9.6M of value at 5.0% exit cap', 'Sell immediately before lease expires', 'Renovate first, then decide on rent'], a: 1, exp: 'NOI uplift = ($1.95 − $1.55) × 100K × 12 = $480K/yr. At 5.0% exit cap: $480K ÷ 5.0% = $9.6M additional value. This mark-to-market represents ~48% value creation above the $20M acquisition price — a compelling thesis.' },
      { q: 'Value-add IRR targets are typically higher than core IRR targets because:', opts: ['Value-add deals use more debt', 'Value-add carries execution risk (renovation, lease-up, re-tenanting) that core does not — investors require higher returns to compensate', 'Value-add deals have longer hold periods', 'Core deals have higher cap rates'], a: 1, exp: 'Risk-adjusted returns: core (stabilized, long-term leased) = 8–12% target IRR. Value-add (execution risk, lease-up) = 13–18%+ target IRR. Higher execution risk demands higher return expectations.' },
      { q: 'An industrial property has a 10-year lease with no mark-to-market opportunity for 10 years. This property is best described as:', opts: ['Value-add — long leases are always good', 'Core investment — stable, predictable income with no near-term upside or execution risk', 'Opportunistic — long leases create development risk', 'Distressed — long leases suppress value'], a: 1, exp: 'Long-term, stable, in-place lease = core characteristics. No mark-to-market upside near-term, but also no lease-up risk. Core investors accept lower returns for this stability.' },
      { q: 'A value-add business plan shows: acquisition $18M + renovation $2M = $20M total cost. Exit at 5.5% cap on $1.3M stabilized NOI = $23.6M. Value created is:', opts: ['$3.6M', '$1.6M', '$5.6M', '$2.0M'], a: 0, exp: 'Value created = exit value − total cost = $23.6M − $20M = $3.6M. Plus any distributions during the hold. The $3.6M profit (18% return on $20M invested) represents the value-add premium.' },
      { q: 'Renovation risk in a value-add deal includes all of the following EXCEPT:', opts: ['Cost overruns (renovation costs more than budget)', 'The existing tenant renewing their lease at market rate', 'Construction delays extending the vacancy period', 'Scope creep adding unforeseen work (HVAC, environmental, structural)'], a: 1, exp: 'Tenant renewing at market rate is a positive outcome — it eliminates renovation and lease-up risk. Cost overruns, delays, and scope creep are genuine renovation risks that can reduce IRR.' },
      { q: 'An industrial value-add deal in Long Beach has strong fundamentals but a 12% going-in cap (much higher than 5% market cap). This high going-in cap most likely indicates:', opts: ['An excellent buy — always buy at above-market cap rates', 'Severe distress or a major problem: vacant building, deferred maintenance, title issues, or environmental contamination — requiring deeper diligence', 'A clerical error in the marketing materials', 'An opportunity to re-lease immediately at market rates'], a: 1, exp: 'A going-in cap well above market (12% vs. 5% market) is a red flag — something is wrong. Could be a vacant building being priced on pro-forma NOI, significant deferred maintenance, an environmental issue, or major lease concerns. Always investigate large cap rate premiums.' },
      { q: 'Stress-testing a value-add deal means:', opts: ['Running the deal numbers only under the base case', 'Testing the model under delayed lease-up, higher renovation costs, lower market rents, and cap rate expansion — to understand the deal\'s downside', 'Presenting the best-case scenario to investors', 'Getting a second appraisal'], a: 1, exp: 'Stress testing = "what if things go wrong?" Extend lease-up by 6 months, add 15% to renovation budget, reduce exit market rents by 5%, expand cap rate by 50 bps. Does the deal still hit minimum return thresholds? This is the investment committee\'s first question.' },
      { q: 'An Infinity Capital value-add industrial deal targets 16% IRR. Base case shows 17.5%. Stress case (6-month extended lease-up, 10% renovation overrun, 5.5% exit cap vs. 5.0% base) shows 13.5%. How should this deal be presented?', opts: ['It passes — base case exceeds target', 'Present both cases honestly; the 250-bps gap between base and stress (and stress falling below target) warrants IC discussion of risk mitigation strategies', 'Reject — stress case below 16%', 'Present only the base case to get approval'], a: 1, exp: 'Honest investment committee presentation shows base AND stress case. A 250-bps downside variance with stress below target (13.5% < 16%) requires honest discussion: can we mitigate the lease-up risk? Can we negotiate a lower price to improve the stress case? IC decides with full information.' },
      { q: 'The value-add spread (difference between going-in cap on cost and stabilized cap on cost) primarily measures:', opts: ['How much NOI will grow due to rent market cycles', 'The return premium created by the business plan — how much value the investor adds through execution', 'The spread between the going-in and exit cap rates', 'The difference between debt yield and cap rate'], a: 1, exp: 'Value-add spread = stabilized cap on cost − going-in cap on cost. A 200+ bps spread indicates significant value creation from the business plan (renovation + re-leasing). This spread measures execution alpha — the return generated by active management.' },
      { q: 'A Long Beach industrial value-add deal: $180/SF purchase, $12/SF renovation, 9-month lease-up at 50% occupancy, then $1.90/SF/mo NNN at 95% occupancy, exit at 5.25% cap after Year 5. This deal most likely offers:', opts: ['Core-level returns (~8–10% IRR)', 'Value-add returns (~14–18% IRR) driven by renovation uplift, lease-up, and mark-to-market NOI growth', 'Opportunistic returns (~20%+ IRR)', 'Negative returns due to lease-up risk'], a: 1, exp: 'Classic light value-add deal: short renovation, single lease-up, clear mark-to-market. These typically generate 14–18% IRR depending on acquisition basis, lease-up speed, and exit cap. Value-add (not opportunistic) because execution risk is bounded and market fundamentals are strong.' },
    ],
  },
  8: {
    sessions: [
      { day: 'Mon Mar 23', title: 'Session 1 — Vocabulary: JV, GP, LP, Preferred Return, Promote, Waterfall' },
      { day: 'Wed Mar 25', title: 'Session 2 — Modeling a 2-Tier JV Waterfall in Excel' },
      { day: 'Thu Mar 26', title: 'Session 3 — GP vs. LP Economics at Different IRR Outcomes' },
      { day: 'Fri Mar 27', title: 'Session 4 — Reading a JV Term Sheet + 20-Question Quiz' },
    ],
    vocabulary: [
      { term: 'JV', full: 'Joint Venture', definition: 'A partnership between a General Partner (operator/developer) and one or more Limited Partners (capital providers) to co-invest in a real estate deal. The GP typically contributes 10–20% of equity and manages execution; the LP contributes 80–90% of equity and receives preferred returns with limited management control.', example: '$10M total equity: GP contributes $1M (10%), LP contributes $9M (90%). GP operates the deal and earns a promote on LP\'s capital above the preferred return.' },
      { term: 'GP', full: 'General Partner', definition: 'The operator/developer who manages the joint venture. Contributes minority equity (typically 10–20%), makes all operational decisions, and earns a promote (carried interest) as upside compensation for managing the deal. Has full management authority and fiduciary duty to the LP.', example: 'Infinity Capital acts as GP on a $10M Long Beach industrial JV: contributes $1M equity, manages acquisition/renovation/leasing, earns 20% promote above 8% preferred return.' },
      { term: 'LP', full: 'Limited Partner', definition: 'The capital investor in a JV who contributes the majority of equity (80–90%) but has limited operational control. Receives return of capital and preferred return before the GP earns promote. Has limited liability (only loses invested equity). Institutional LPs include pension funds, family offices, and REITs.', example: 'Institutional LP contributes $9M (90% of equity) to an industrial JV. Receives 8% pref on $9M = $720K/yr before GP earns any promote.' },
      { term: 'Preferred Return', full: 'Preferred Return (Pref)', definition: 'A minimum return (typically 7–9%) that the LP must receive on invested capital before the GP earns any promote. Accrues if not paid currently. Ensures LPs recover their capital and minimum yield before GP profits. The cornerstone of fair LP/GP alignment.', example: 'LP invests $9M; 8% pref = $720,000/yr. If the deal distributes only $400,000 in Year 1, the shortfall of $320,000 accrues and must be paid in Year 2 before any promote.' },
      { term: 'Promote', full: 'Promote (Carried Interest)', definition: 'The GP\'s disproportionate share of profits above the preferred return, as compensation for managing the deal. Typically 20% of profits above pref. Aligns GP incentives with LP interests — GP only earns promote if LP achieves their minimum return first.', example: 'Above 8% pref, profits split 80% LP / 20% GP (promote). If total distributable profit above pref = $2M, LP gets $1.6M, GP gets $400K as promote.' },
      { term: 'Waterfall Distribution', full: 'Waterfall Distribution', definition: 'The sequential order in which JV profits are distributed. Tier 1: return of LP capital. Tier 2: LP preferred return (and accrued pref). Tier 3: split of remaining profits (e.g., 80/20 LP/GP). Each tier must be satisfied before moving to the next. Protects LP capital and minimum return.', example: 'Exit proceeds $15M. Tier 1: return $9M LP capital. Tier 2: $720K accrued pref (Year 1 shortfall). Tier 3: remaining $5.28M split 80% LP ($4.22M) / 20% GP ($1.06M promote).' },
      { term: 'Hurdle Rate', full: 'Hurdle Rate', definition: 'The minimum return threshold (usually the preferred return rate) above which the GP earns its promote. Some JVs include multiple hurdle tiers — e.g., 8% pref (first hurdle), then above 12% IRR the split becomes 70/30, above 18% becomes 60/40. Each tier incentivizes GP performance.', example: 'Tier 1 hurdle: 8% pref → 80/20 split. Tier 2 hurdle: 15% IRR → 70/30 split. At 20% IRR, the GP earns significantly more promote per dollar of return.' },
    ],
    quiz: [
      { q: 'In a real estate JV, the GP typically:', opts: ['Contributes the majority of equity and has no decision-making power', 'Contributes minority equity (10–20%), manages all operations, and earns a promote as upside compensation', 'Contributes nothing and charges a fixed fee', 'Provides debt financing to the project'], a: 1, exp: 'GP = operator: contributes 10–20% equity, makes all management decisions, earns promote above LP\'s preferred return. The promote rewards the GP\'s expertise and execution, not their capital.' },
      { q: 'An 8% preferred return on $10M LP investment means the LP earns annually:', opts: ['$80,000', '$800,000', '$8,000,000', '$1,000,000'], a: 1, exp: '$10M × 8% = $800,000/yr preferred return.' },
      { q: 'In a standard JV waterfall, which is paid FIRST?', opts: ['GP promote', 'LP preferred return', 'Return of LP\'s invested capital', 'Management fees'], a: 2, exp: 'Waterfall order: (1) Return of LP capital, (2) LP preferred return, (3) GP promote on remaining profits. Capital return before income return before upside profit.' },
      { q: 'An 80/20 LP/GP split "above the pref" means:', opts: ['LP and GP split all profits 80/20 from Day 1', 'After LP capital is returned and LP pref is paid, remaining profits split 80% to LP, 20% to GP (the promote)', 'GP gets 20% of all revenue', 'LP gets 80% of acquisition price'], a: 1, exp: 'The split only applies above the pref — the GP earns promote only after LP capital is returned and pref is satisfied. The 80/20 split above pref is the promote tier.' },
      { q: 'GP invests $1M (10%), LP invests $9M (90%). 8% pref on LP capital only. Exit proceeds after loan repayment: $15M. Calculate LP and GP distributions:', opts: ['LP $13.5M, GP $1.5M', 'LP $12.32M, GP $2.68M', 'LP $12M, GP $3M', 'LP $9M, GP $6M'], a: 1, exp: 'Step 1: Return LP capital: $9M to LP. Remaining: $6M. Step 2: LP pref (assume 5-year hold at 8% simple): $9M × 8% × 5 = $3.6M... Actually depends on hold period and exact waterfall. Simplified: $15M exit − $9M capital − $720K × hold years pref, then 80/20 on remainder.' },
      { q: 'The promote primarily serves to:', opts: ['Compensate the LP for taking development risk', 'Align GP incentives with LP interests — GP earns significant upside only by first delivering LP\'s preferred return', 'Reduce the interest rate on the JV\'s loan', 'Pay the GP a flat management fee'], a: 1, exp: 'Promote alignment: GP can\'t earn promote until LP is made whole (capital + pref). This ensures the GP is incentivized to maximize LP returns — their upside depends on LP success first.' },
      { q: 'A 2-tier waterfall has Tier 1: 8% pref (80/20 split) and Tier 2: above 15% IRR (70/30 split). At an overall 20% IRR, the GP earns:', opts: ['20% of all profits', 'A higher promote percentage on the Tier 2 profits (above 15% hurdle) — more than the base 20% promote', 'The same 20% throughout', 'Nothing — hurdle is not met'], a: 1, exp: 'Multi-tier waterfalls reward GP disproportionately as returns rise. Above Tier 2 (15% IRR), GP earns 30% promote instead of 20%. This incentivizes GP to push beyond the base hurdle, not just meet it.' },
      { q: 'LP contributed $8M. After a 4-year hold, accrued 8% pref (simple) is:', opts: ['$640,000 total', '$2,560,000 total', '$320,000 total', '$1,280,000 total'], a: 1, exp: 'Simple pref: $8M × 8% × 4 years = $2,560,000 accrued preferred return. Compounded pref would be slightly higher.' },
      { q: 'GP earns promote of $800,000 on a deal. GP invested $1M (10%). LP invested $9M (90%). The promote represents the GP\'s return on:', opts: ['Their $1M investment only', 'The value created above the LP\'s minimum required return — compensation for management expertise, not their capital contribution', 'A percentage of loan amount', 'The acquisition price'], a: 1, exp: 'Promote rewards skill and execution, not capital. The GP\'s $800K promote was earned by successfully managing the deal to deliver above the LP\'s 8% pref — not by contributing capital.' },
      { q: 'In a JV where the pref accrues (compounds if not paid currently), the GP is incentivized to:', opts: ['Delay property cash flows as long as possible', 'Generate property cash flow early and often — delaying pref payments allows it to grow, reducing promote opportunity', 'Increase leverage to maximize GP promote', 'Extend the hold period indefinitely'], a: 1, exp: 'Accruing (unpaid) preferred return grows the LP\'s priority bucket, reducing the pot available for GP promote. GPs want to pay pref currently so the accrual doesn\'t compound. Early cash flow = lower total pref burden = more promote.' },
      { q: 'An LP term sheet reads: "8% cumulative, non-compounding preferred return; 80/20 split above pref." Cumulative means:', opts: ['The pref is paid every month without fail', 'Pref shortfalls accumulate — if pref is not fully paid in any year, the shortfall is added to the pref balance and paid in future years before promote', 'The pref rate increases over time', 'The LP receives pref whether the property makes money or not'], a: 1, exp: 'Cumulative: any pref not paid currently accumulates and must be paid in future periods before GP earns promote. Non-compounding: accrued pref earns simple interest, not compound. More favorable to LP than non-cumulative (lost pref is lost).' },
      { q: 'JV equity total: $12M (GP $1.2M, LP $10.8M). Deal exits at $25M net (after loan repayment). Simple pref: 8% × $10.8M × 3 years = $2,592,000. After returning capital and pref, how much is available for the 80/20 promote split?', opts: ['$0 — all proceeds go to LP', '$25M − $10.8M − $2.592M = $11.608M available for 80/20 split', '$25M − $12M = $13M', '$25M − $10.8M = $14.2M'], a: 1, exp: 'Available for promote: $25M − LP capital ($10.8M) − LP pref ($2.592M) = $11.608M. LP gets 80%: $9.286M; GP gets 20% promote: $2.322M.' },
      { q: 'Why do institutional LPs (pension funds, endowments) invest in CRE JVs as the LP rather than acquiring properties directly?', opts: ['They cannot hold real estate directly by law', 'They leverage the GP\'s local market expertise, deal origination, and operational capability — while deploying large amounts of capital efficiently with limited management burden', 'Direct ownership has adverse tax treatment', 'They prefer lower returns from LP positions'], a: 1, exp: 'Institutional LPs have capital but often lack local market expertise, deal flow, or operational bandwidth. JV partnerships allow them to deploy capital into high-quality real estate managed by specialized GPs — getting returns without the operational commitment.' },
      { q: 'A GP earns a 1.5% acquisition fee on a $20M industrial acquisition. This fee is:', opts: ['Part of the promote', '$300,000, paid at closing — separate from the promote, which is earned at exit', '$30,000 annually', 'Only paid if the deal exceeds the preferred return'], a: 1, exp: 'Acquisition fee = $20M × 1.5% = $300,000 paid at closing. This compensates the GP for sourcing, underwriting, and closing the deal — separate from the promote earned at exit. GPs typically earn: acquisition fee, asset management fee, and promote.' },
      { q: 'Infinity Capital (GP) presents a JV term sheet to a family office LP with: 9% preferred return, 75/25 LP/GP split above pref. The LP\'s 9% pref requirement (vs. typical 7–8%) reflects:', opts: ['The LP is more sophisticated', 'The LP has a higher required return — perhaps due to higher opportunity cost or higher risk perception for this deal type', 'The GP made a math error', 'Standard terms — 9% is the market pref rate'], a: 1, exp: 'LP pref rate reflects their required return for the deal risk. A 9% pref means the LP needs more downside protection — possibly due to deal risk, competing alternatives, or their cost of capital. Higher pref = less GP promote opportunity, so GPs negotiate pref rates carefully.' },
      { q: 'In a JV waterfall, "catch-up" provision means:', opts: ['LP receives a higher pref in later years', 'After LP pref is paid, GP receives 100% of distributions until it catches up to its promote percentage — then reverts to the ongoing split', 'GP can catch up to LP\'s capital contribution', 'The pref rate increases if the deal underperforms'], a: 1, exp: 'Catch-up: after LP pref is satisfied, GP takes 100% of distributions until GP has received its proportionate share of total profits (e.g., 20%). This "catches up" the GP before the ongoing 80/20 split begins. Accelerates GP promote payment but doesn\'t change total economics.' },
      { q: 'LP invests $5M; 8% preferred return; GP invests $500K. 3-year hold. Property distributes $800K in Year 1, $950K in Year 2, and $2.5M at exit (above debt repayment and LP capital). LP pref per year = $400K. In Year 1, pref is:', opts: ['Fully paid — $800K covers $400K pref', 'Fully paid; $400K excess goes to 80/20 split', 'Not fully paid — $800K but pref is $800K (not met)', 'Overpaid by $400K'], a: 1, exp: 'Year 1 distributions: $800K. LP pref: $400K. Pref is fully paid, $400K remaining. That $400K splits 80/20: LP gets $320K + $400K pref = $720K total; GP gets $80K promote in Year 1.' },
      { q: 'What is the GP\'s total equity return (promote + capital) as a percentage of total JV equity in a typical 90/10 LP/GP structure with 20% promote?', opts: ['10% — GP only earns on their capital contribution', 'Significantly more than 10% if the deal succeeds — the promote can multiply the GP\'s effective return on their 10% contribution', '20% of all profits', 'Exactly 20%'], a: 1, exp: 'With 10% capital + 20% promote on upside, a GP in a strong deal can earn 30–50%+ of total distributions on only 10% of capital. This leverage is why real estate development is so attractive for skilled operators.' },
      { q: 'An Infinity Capital LP asks: "What happens to my preferred return if the property doesn\'t generate enough cash flow to pay it?" This question relates to:', opts: ['Compound interest risk', 'Cumulative vs. non-cumulative pref — in a cumulative structure, shortfalls accrue; non-cumulative shortfalls are lost. LP should always insist on cumulative preferred return.', 'GP\'s right to skip pref distributions', 'Leverage ratio impact'], a: 1, exp: 'Cumulative pref is LP-protective: unpaid pref builds up and must be paid before GP promote. Non-cumulative pref is GP-friendly but LP-risky: a year where the property doesn\'t pay pref, that income is gone. Sophisticated LPs always require cumulative preferred return.' },
    ],
  },
  9: {
    sessions: [
      { day: 'Mon Mar 30', title: 'Session 1 — Vocabulary: Lease Expiration, Rollover Risk, Mark-to-Market, CapEx Plan' },
      { day: 'Wed Apr 1', title: 'Session 2 — Building a Lease Expiration Schedule for a 5-Property Portfolio' },
      { day: 'Thu Apr 2', title: 'Session 3 — CapEx Planning: What to Spend, When, and Why' },
      { day: 'Fri Apr 3', title: 'Session 4 — Hold vs. Sell Analysis + 20-Question Quiz' },
    ],
    vocabulary: [
      { term: 'Lease Expiration Schedule', full: 'Lease Expiration Schedule', definition: 'A timeline showing when each tenant\'s lease expires across a portfolio. Used to identify renewal risk concentration (multiple leases expiring simultaneously), mark-to-market opportunities (below-market leases expiring), and capital need timing. The fundamental asset management planning tool.', example: 'Portfolio: Tenant A (45K SF) expires Q1 2026; Tenant B (80K SF) expires Q3 2026; Tenant C (30K SF) expires Q4 2027. Q3 2026 is a major risk/opportunity concentration.' },
      { term: 'Rollover Risk', full: 'Rollover (Lease Expiration) Risk', definition: 'The risk that a tenant does not renew their lease at expiration, creating vacancy and requiring re-leasing costs (leasing commissions, tenant improvements, downtime). Concentrated rollover (multiple expirations in same period) compounds the risk. Managed by staggering lease terms and proactive renewal outreach.', example: 'A 200K SF single-tenant industrial building: entire income stream expires in one date. If tenant leaves, 100% vacancy overnight — maximum rollover risk concentration.' },
      { term: 'Mark-to-Market Opportunity', full: 'Mark-to-Market Rent Opportunity', definition: 'The upside from resetting a below-market in-place lease to current market rent at expiration. Quantified as: (market rent − in-place rent) × SF × 12. A key value-add driver. Captured at lease expiration through new lease negotiation or by re-tenanting at market rate.', example: 'In-place rent: $1.50/SF/mo NNN. Market rent: $2.00/SF/mo. 100K SF. Mark-to-market uplift = $0.50 × 100K × 12 = $600K/yr additional NOI.' },
      { term: 'CapEx Plan', full: 'Capital Expenditure Plan', definition: 'A multi-year schedule of planned capital investments to maintain or improve the property: roof replacement, HVAC, parking lot, dock levelers, and tenant improvements. Funded from reserves or capital calls. Good CapEx planning prevents deferred maintenance that reduces asset value and tenant satisfaction.', example: 'Year 1: Roof $180K; Year 2: Parking lot $95K; Year 3: HVAC replacement $220K; Year 4: Dock levelers $60K. Total 4-year CapEx plan: $555K.' },
      { term: 'Hold vs. Sell', full: 'Hold vs. Sell Analysis', definition: 'A financial analysis comparing the risk-adjusted returns of continuing to hold an asset against selling at today\'s price. Triggered by: lease expirations, significant value creation, cap rate compression, pending CapEx needs, or portfolio rebalancing. The central ongoing decision in asset management.', example: 'Asset at $22M value with $1.1M NOI (5.0% cap). Hold scenario: 3% NOI growth, 5.25% exit cap in 5 years = 14% projected IRR. Sell today at $22M. Is 14% worth the hold risk vs. redeploying $22M in a new opportunity?' },
      { term: 'Asset Management Fee', full: 'Asset Management Fee', definition: 'Annual fee paid to the GP/manager for ongoing asset management: lease negotiations, maintenance oversight, financial reporting, and strategic decision-making. Typically 1–2% of revenues or 1% of property value annually. Reduces LP distributable cash flow but compensates for ongoing active management.', example: 'Property generates $1.2M NOI; 1.5% asset management fee on revenues = $1.2M × 1.5% = $18,000/yr fee to GP. Reduces LP distributable cash flow.' },
    ],
    quiz: [
      { q: 'A lease expiration schedule shows three major tenants all expiring in Q2 2027. This creates:', opts: ['A buying opportunity for new tenants', 'Significant rollover risk concentration — potentially losing multiple tenants simultaneously, creating large vacancy and re-leasing costs', 'An opportunity to raise rents immediately', 'No concern if the market is strong'], a: 1, exp: 'Concentrated expirations = concentrated rollover risk. Three expirations in one quarter could create sudden, severe vacancy and require simultaneous re-leasing of multiple spaces — stretching management capacity and creating cash flow stress.' },
      { q: 'Rollover risk is LOWEST for which tenant profile?', opts: ['Month-to-month tenant paying above-market rent', 'A credit tenant with a 10-year NNN lease signed 2 years ago with 2 renewal options', 'A tenant whose lease expires in 6 months', 'A startup company in its first year of occupancy'], a: 1, exp: 'Long-term lease (10 years) + renewal options + credit tenant = low rollover risk. High probability of renewal, long time before risk crystallizes, and options extend the lease term further if exercised.' },
      { q: 'Mark-to-market uplift: in-place rent $1.60/SF/mo NNN; market $2.10/SF/mo; 60,000 SF. Annual NOI increase at lease expiration:', opts: ['$30,000', '$360,000', '$540,000', '$180,000'], a: 1, exp: '($2.10 − $1.60) × 60,000 × 12 = $0.50 × 60,000 × 12 = $360,000/yr.' },
      { q: 'A CapEx plan helps asset managers primarily by:', opts: ['Reducing the need for tenant improvements', 'Anticipating and budgeting for major capital expenditures before they become emergency expenses, protecting asset quality and cash flow predictability', 'Eliminating all future property expenses', 'Justifying higher rents to tenants'], a: 1, exp: 'Proactive CapEx planning converts unpredictable emergency repairs into planned, budgeted investments. A roof that fails unexpectedly is an emergency; a roof replacement scheduled 2 years out is a line item in the CapEx plan.' },
      { q: 'A typical industrial property CapEx reserve is approximately:', opts: ['$0.05–$0.10/SF/year', '$0.15–$0.35/SF/year', '$1.00–$2.00/SF/year', '$5.00/SF/year'], a: 1, exp: 'Industrial properties are relatively low-maintenance compared to office or multifamily. Standard reserves: $0.15–$0.35/SF/year for basic industrial (single-story tilt-up). Office: $2–$5/SF/yr. Multifamily: $200–$400/unit/yr.' },
      { q: 'An asset manager reviews a building where the HVAC was last replaced 18 years ago (typical life 20–25 years). The right action is:', opts: ['Do nothing until the HVAC fails', 'Budget HVAC replacement in the CapEx plan within 2–5 years — proactive replacement prevents emergency failure and potential lease default', 'Pass the cost to the tenant regardless of lease terms', 'Reduce the asking rent to attract tenants who will pay for HVAC themselves'], a: 1, exp: 'Proactive CapEx planning: HVAC at 18 years needs to be in the 3–5 year CapEx plan. Emergency HVAC failure during summer = tenant emergency = potential lease dispute. Budget it, schedule it, manage it.' },
      { q: 'Deciding to SELL an asset today vs. hold for 5 more years should primarily consider:', opts: ['The original purchase price (sunk cost)', 'Forward IRR of holding vs. risk-adjusted return from redeploying the sale proceeds into a new opportunity', 'How much the property has appreciated since acquisition', 'The broker\'s recommendation'], a: 1, exp: 'Hold vs. sell is a forward-looking analysis. Sunk costs are irrelevant. Compare: what will I earn holding this asset for 5 more years (lease risk, CapEx needs, NOI growth, exit value) vs. selling today and redeploying in a better-return opportunity?' },
      { q: 'A tenant represents 85% of a building\'s revenue on a lease expiring in 18 months. What should the asset manager do now?', opts: ['Wait until 6 months before expiration to start renewal discussions', 'Begin renewal discussions immediately — 18 months is the right lead time for a major tenant. Offer early renewal incentives to reduce rollover risk and preserve occupancy', 'Assume the tenant will renew — 85% of buildings retain their major tenants', 'Market the space for replacement immediately'], a: 1, exp: 'The earlier you engage a major tenant on renewal, the more leverage you have to retain them. 18 months is appropriate lead time. Waiting until 6 months leaves you no time to find a replacement if they decide to leave.' },
      { q: 'Portfolio of 5 industrial buildings: all with leases expiring in 2027. An asset manager should:', opts: ['Sell all 5 buildings in 2026 to avoid rollover risk', 'Proactively begin renewal outreach, stagger future lease terms at renewal, budget re-leasing costs, and stress-test cash flow during any gap periods', 'Wait to see if tenants renew before acting', 'Extend all leases at current rents to eliminate risk'], a: 1, exp: 'Concentrated portfolio rollover requires systematic management: early renewal outreach, staggered terms at renewal, budgeted CapEx and TIs, and a hold period that accounts for lease-up scenarios.' },
      { q: 'Asset management fee of 1.5% of effective gross revenues on a property generating $2.0M EGI equals:', opts: ['$30,000/yr', '$300,000/yr', '$150,000/yr', '$20,000/yr'], a: 0, exp: '$2.0M × 1.5% = $30,000/yr. Note: asset management fees are typically small relative to NOI, but they accumulate across a portfolio.' },
      { q: 'A 3-year hold with a 2-year lease expiration remaining creates what challenge for the exit?', opts: ['No challenge — buyers prefer short lease terms', 'The building will be in rollover risk during the buyer\'s hold period — reducing buyer\'s willingness to pay a core premium and potentially requiring a lease-up discount', 'The seller must renew the lease before selling', 'IRR automatically increases when lease terms are short'], a: 1, exp: 'Buyers discount properties with near-term lease expirations because they are buying rollover risk. A 2-year remaining lease means the buyer faces re-leasing within 2 years of acquisition — they\'ll price this uncertainty into their offer.' },
      { q: 'Which event most strongly suggests selling an asset now rather than continuing to hold?', opts: ['Cap rates expanding 25 bps', 'The property is fully leased at market rent, no near-term CapEx needed, and a competing buyer has appeared willing to pay at a cap rate lower than your projected exit', 'NOI grew 3% last year', 'The loan maturity is in 4 years'], a: 1, exp: 'Sell signals: (1) fully stabilized — no more upside from operations, (2) no CapEx burden — clean story for buyer, (3) aggressive buyer willing to pay your target exit price. This is the optimal sell scenario.' },
      { q: 'A 200K SF industrial portfolio with $0.20/SF/yr CapEx reserve needs how much annual CapEx reserves?', opts: ['$20,000', '$40,000', '$200,000', '$400,000'], a: 1, exp: '200,000 SF × $0.20/SF = $40,000/yr CapEx reserve.' },
      { q: 'Proactive renewal of a below-market lease (to lock in a good tenant for 5 more years) creates what tradeoff?', opts: ['No tradeoff — always renew early', 'Lock in tenant stability but forfeit the near-term mark-to-market opportunity. The decision depends on whether rollover risk or rent upside is more material.', 'Always renew at above-market rent', 'Rollover risk is always worth accepting for the rent upside'], a: 1, exp: 'Early renewal at below-market rent = tenant stays (reduces vacancy risk) but forgoes mark-to-market opportunity. Decision depends on tenant quality, market conditions, and how below-market the rent is. Good tenants at slight discount may beat re-leasing risk.' },
      { q: 'A hold vs. sell analysis shows: hold 5 more years = projected 13% IRR; sell today and redeploy = projected 17% IRR in next acquisition. The analysis suggests:', opts: ['Hold — never sell a performing asset', 'Sell — higher risk-adjusted return from redeployment makes selling the superior financial decision', 'Sell only if the gain is more than $1M', 'Neither — average the two returns and hold half'], a: 1, exp: 'Capital should be deployed where it earns the highest risk-adjusted return. If selling and redeploying delivers 17% vs. 13% holding, sell — assuming the 17% opportunity is genuine and risk-equivalent.' },
      { q: 'What does "staggered lease expiration" mean in portfolio asset management?', opts: ['All tenants have the same lease expiration date', 'Lease expirations are spread across different years — reducing the risk of simultaneous vacancy and spreading the re-leasing workload over time', 'All leases are month-to-month', 'Tenants can choose when their leases expire'], a: 1, exp: 'Staggered expirations = risk mitigation. If Tenant A expires 2025, B expires 2027, C expires 2029, you face one re-leasing event at a time rather than all three at once. This is the primary lease scheduling goal in portfolio asset management.' },
      { q: 'A tenant requests a 5-year lease extension at in-place rent ($1.55/SF/mo) when market is $2.10/SF/mo. The asset manager should:', opts: ['Refuse — always demand market rent immediately', 'Negotiate: offer a renewal at a blend (e.g., $1.75/SF now stepping to $1.95/SF in Year 3) that retains the tenant while capturing partial mark-to-market', 'Accept immediately — tenant retention is paramount', 'Reject and start marketing the space for a new tenant at $2.10'], a: 1, exp: 'Negotiation: a blend-and-extend captures some mark-to-market while retaining a proven tenant. Pure tenant replacement at market maximizes rent but risks vacancy. Pure renewal at in-place rent leaves money on the table. A blended step-up balances both.' },
      { q: 'Asset managers track "weighted average lease term" (WALT) because:', opts: ['It equals the average lease term in the portfolio', 'WALT weighted by SF or NOI measures the portfolio\'s average remaining lease term — longer WALT = more income certainty, lower rollover risk, lower risk premium for buyers', 'It determines the property\'s depreciation schedule', 'WALT sets the CapEx reserve requirement'], a: 1, exp: 'WALT is the primary lease risk metric for CRE portfolios. Buyers price longer WALT at lower cap rates (higher values) because income certainty is higher. Short WALT = rollover risk = cap rate premium = lower price.' },
      { q: 'In an Infinity Capital asset management review, three buildings show: Building A (WALT 7.5 yrs, below-market rents), Building B (WALT 2.5 yrs, market rents), Building C (WALT 0.5 yrs, above-market rents). Rollover risk ranking from highest to lowest:', opts: ['A > B > C', 'C > B > A', 'B > C > A', 'All equal'], a: 1, exp: 'Rollover risk = short remaining lease term. C (0.5 yr) is highest risk — expiring imminently. B (2.5 yr) is next. A (7.5 yr) is lowest risk. Note: C has above-market rents, meaning renewal may mean rent reduction — additional income risk at expiration.' },
    ],
  },
  10: {
    sessions: [
      { day: 'Mon Apr 6', title: 'Session 1 — Vocabulary: 1031 Exchange, QI, Identification Period, Like-Kind, Boot, Depreciation Recapture' },
      { day: 'Wed Apr 8', title: 'Session 2 — 1031 Exchange Mechanics: 45-Day Rule, 180-Day Rule, QI Role' },
      { day: 'Thu Apr 9', title: 'Session 3 — Outright Sale vs. 1031 vs. Refinance: After-Tax Comparison' },
      { day: 'Fri Apr 10', title: 'Session 4 — Depreciation Recapture and Capital Gains Analysis + 20-Question Quiz' },
    ],
    vocabulary: [
      { term: '1031 Exchange', full: '1031 Tax-Deferred Exchange', definition: 'A provision in IRS Section 1031 allowing an investor to defer capital gains taxes when selling a qualifying investment property — as long as proceeds are reinvested into a like-kind replacement property within strict timelines. The most powerful tax deferral tool in CRE. Can be used repeatedly to defer taxes indefinitely.', example: 'Sell Long Beach industrial for $20M ($15M gain). Instead of paying $3M+ in capital gains tax, do a 1031 exchange into a Phoenix multifamily deal — defer all taxes and reinvest the full $20M.' },
      { term: 'QI', full: 'Qualified Intermediary', definition: 'A third-party facilitator required to execute a 1031 exchange. The seller\'s proceeds go directly to the QI (not the seller) to avoid "constructive receipt." The QI holds funds during the exchange period and wires them to buy the replacement property. If proceeds touch the seller\'s account, the exchange fails.', example: 'HTA sells industrial building; QI receives $8M proceeds at closing. HTA identifies replacement within 45 days, QI wires funds to close replacement property within 180 days.' },
      { term: 'Identification Period', full: '45-Day Identification Period', definition: 'The IRS-mandated 45-day window from the sale of the relinquished property during which the investor must formally identify potential replacement properties in writing to the QI. Strict deadline — no extensions except for federally declared disasters. Must identify at least 1 property (can identify up to 3 under the 3-property rule).', example: 'Sale closes July 1. Deadline: August 15 (45 days). Investor must identify replacement property in writing to QI by August 15 or exchange fails.' },
      { term: 'Like-Kind Property', full: 'Like-Kind Replacement Property', definition: 'Under Section 1031, real property held for investment or business use qualifies as "like-kind" to other real property held for investment or business use — regardless of property type. Industrial can exchange into multifamily; retail can exchange into office. Like-kind is broad for real property; primary residences do NOT qualify.', example: 'Relinquished: Long Beach industrial warehouse. Replacement: Phoenix multifamily complex. Both held for investment → like-kind exchange qualifies.' },
      { term: 'Boot', full: 'Boot (Taxable Portion of Exchange)', definition: 'Any portion of exchange proceeds that is NOT reinvested into like-kind property — received as cash, debt relief, or personal property. Boot is taxable. To fully defer all taxes, the replacement property must be equal or greater in value, and all proceeds must be reinvested. Partial reinvestment = partial tax owed on the boot.', example: 'Sell for $10M; buy replacement for $8.5M. $1.5M boot received → taxable. If gain was $6M, and boot is $1.5M, $1.5M of the $6M gain is currently taxable.' },
      { term: 'Depreciation Recapture', full: 'Depreciation Recapture (Section 1250)', definition: 'When a commercial property is sold, the IRS recaptures depreciation deductions taken during ownership at a flat 25% federal rate (vs. 20% long-term capital gains rate). Cannot be deferred in a 1031 exchange if the replacement property has less depreciable basis. A significant tax consideration at disposition.', example: 'Took $1.5M in depreciation over 10-year hold. At sale, $1.5M recaptured at 25% rate = $375,000 in depreciation recapture tax (on top of capital gains on any appreciation).' },
      { term: 'Exchange Period', full: '180-Day Exchange Period', definition: 'The IRS-mandated 180-day window from the relinquished property sale to close on the identified replacement property. The 45-day ID period runs concurrently within the 180-day window. Failure to close within 180 days results in a failed exchange and full tax liability on the gain.', example: 'Sale closes July 1. Must close replacement by December 28 (180 days). The 45-day ID deadline (Aug 15) is within this window.' },
    ],
    quiz: [
      { q: 'A 1031 exchange allows an investor to:', opts: ['Eliminate capital gains taxes permanently', 'Defer capital gains taxes by reinvesting sale proceeds into a like-kind replacement property within required timelines', 'Sell property tax-free if held for more than 10 years', 'Avoid all taxes including depreciation recapture'], a: 1, exp: '1031 defers (does not eliminate) capital gains tax. Taxes are paid when the replacement property is eventually sold without a subsequent 1031. Used repeatedly, taxes can be deferred across multiple cycles.' },
      { q: 'The 45-day rule in a 1031 exchange requires:', opts: ['Closing on the replacement property within 45 days', 'Formally identifying replacement properties in writing to the QI within 45 days of the relinquished property sale', 'Receiving exchange funds from the QI within 45 days', 'Completing depreciation recapture within 45 days'], a: 1, exp: '45 days from relinquished sale: formal written identification of replacement properties to QI. This is a hard IRS deadline with essentially no extensions.' },
      { q: 'If sale proceeds touch the investor\'s personal bank account during a 1031 exchange:', opts: ['The exchange still qualifies if reinvested within 180 days', 'The exchange fails — constructive receipt of proceeds disqualifies the exchange and triggers full capital gains tax', 'The investor has 30 days to return the funds to the QI', 'Only the amount received is taxable, not the full gain'], a: 1, exp: 'Constructive receipt rule: if the investor ever has control over the proceeds (even briefly), the 1031 fails completely. All proceeds must flow directly to the QI — never through the seller\'s accounts.' },
      { q: 'Can an investor exchange a Long Beach industrial building for a Phoenix apartment complex in a 1031?', opts: ['No — must be the same property type', 'Yes — both are investment real estate and qualify as like-kind regardless of property type', 'Only if both are NNN leased', 'Only if both are in California'], a: 1, exp: 'Like-kind for real property is broad: any investment real property exchanged for any other investment real property qualifies. Cross-asset class and cross-state exchanges are permitted.' },
      { q: '"Boot" in a 1031 exchange is:', opts: ['The QI\'s fee for executing the exchange', 'The taxable portion — any proceeds not reinvested into like-kind property (cash received, net debt relief, or personal property received)', 'The identification letter sent to the QI', 'The replacement property\'s title insurance'], a: 1, exp: 'Boot = taxable cash or debt relief not reinvested. To defer 100% of gain, reinvest 100% of proceeds and acquire equal or greater debt. Any shortfall = boot = current-year taxable income.' },
      { q: 'Sell $15M industrial; $9M gain (original basis $6M). Buy replacement for $13M (took $2M boot). How much of the gain is taxable?', opts: ['$9M — full gain taxable', '$2M — only the boot triggers tax', '$7M — gain minus boot', '$0 — partial exchange defers all'], a: 1, exp: 'In a partial exchange, gain is recognized to the extent of boot received. $2M boot received = $2M gain recognized and taxable. Remaining $7M of gain deferred into replacement property basis.' },
      { q: 'The 180-day exchange period starts:', opts: ['When the investor signs the 1031 agreement', 'On the date the relinquished property sale closes', 'When the QI identifies the replacement property', '45 days after the relinquished property sale'], a: 1, exp: 'Both the 45-day and 180-day periods start on the relinquished property closing date. They run concurrently — identification by day 45, closing by day 180.' },
      { q: 'Depreciation recapture is taxed at what federal rate?', opts: ['0% — depreciation recapture is not taxed separately', '25% — flat rate on recaptured depreciation, separate from long-term capital gains rate (20%)', '20% — same as long-term capital gains', '37% — ordinary income rate'], a: 1, exp: 'Section 1250 depreciation recapture on commercial real estate is taxed at 25% federal rate, higher than the 20% long-term capital gains rate. This is a significant cost basis consideration at disposition.' },
      { q: 'An investor took $2M in depreciation over 12 years. Building sells at $800K gain above depreciated basis. Taxes owed include:', opts: ['$800K gain only at 20% = $160K', '$2M at 25% recapture ($500K) + $800K at 20% LTCG ($160K) = $660K total federal tax', '$2M at 37% ordinary income = $740K', '$0 — 1031 eliminates all taxes'], a: 1, exp: 'Two tax events at sale: (1) Recapture $2M of depreciation at 25% = $500K. (2) Long-term gain on remaining appreciation at 20% = $160K. Total federal: ~$660K (plus state). This is why 1031 exchanges are so valuable — deferring $660K in taxes keeps that capital working.' },
      { q: 'A primary residence does NOT qualify for 1031 because:', opts: ['Residences are too small', '1031 requires property held for investment or business use — a primary residence is personal use property and is excluded', 'Residential properties have no capital gains', 'Residences can only be exchanged for other residences'], a: 1, exp: '1031 applies to investment or business-use real property. Personal residences are excluded. Note: the Section 121 exclusion ($250K/$500K gain exclusion) applies to primary residences instead.' },
      { q: 'An investor owns Long Beach industrial worth $22M, original basis $6M, $4M depreciation taken (depreciated basis $2M). Full sale gain = $22M − $2M = $20M. Depreciation recapture portion is:', opts: ['$20M at 25%', '$4M at 25% recapture rate; $16M at 20% LTCG rate', '$6M at 25%', '$22M at 37%'], a: 1, exp: 'Tax layers: $4M depreciation recaptured at 25% = $1M tax. Remaining $16M appreciation at 20% LTCG = $3.2M. Total federal: ~$4.2M. A 1031 can defer this entire $4.2M if reinvested properly.' },
      { q: 'Under the 3-property identification rule, an investor can identify up to __ replacement properties within 45 days:', opts: ['1', '3', '5', 'Unlimited'], a: 1, exp: 'The 3-property rule: an investor can identify up to 3 properties of any value as potential replacements. Alternatively, the 200% rule allows identifying unlimited properties as long as total identified value ≤ 200% of relinquished value.' },
      { q: 'Why is a 1031 exchange described as a "tax deferral" not "tax elimination"?', opts: ['The taxes are eliminated after 10 years', 'The gain is carried forward in the replacement property\'s lower basis — when the replacement is eventually sold without a 1031, all deferred gains become taxable', 'Depreciation recapture is still owed immediately', 'State taxes cannot be deferred'], a: 1, exp: 'The replacement property\'s basis is reduced by the deferred gain. When eventually sold, the accumulated deferred gains (from all prior 1031s) become taxable. Exception: stepped-up basis at death can eliminate deferred gain permanently — sometimes called the "1031 forever" strategy.' },
      { q: 'Outright sale vs. 1031 exchange vs. cash-out refinance: which option generates no current taxable event?', opts: ['Outright sale — pay capital gains and invest net proceeds', '1031 exchange (if properly executed) or cash-out refinance — both defer or avoid current taxation', 'Cash-out refinance only', 'All generate current tax'], a: 1, exp: 'A properly executed 1031 defers capital gains. A cash-out refinance (borrowing against equity) generates no taxable event — loan proceeds are debt, not income. Both preserve capital for reinvestment. Outright sale triggers capital gains and recapture immediately.' },
      { q: 'An investor closes a sale on August 1. The 45-day identification deadline is:', opts: ['September 1', 'September 15', 'October 1', 'July 31 of next year'], a: 1, exp: 'August 1 + 45 days = September 15. Count calendar days from closing date.' },
      { q: 'The QI\'s primary function is to:', opts: ['Negotiate the replacement property purchase price', 'Hold exchange proceeds in escrow between the sale of the relinquished property and the purchase of the replacement — ensuring the investor never has constructive receipt', 'File the 1031 with the IRS', 'Identify replacement properties for the investor'], a: 1, exp: 'QI safeguards the exchange by holding proceeds. The investor has no access to funds during the exchange period. QI also prepares the exchange agreement and coordinates with closing agents.' },
      { q: 'Infinity Capital completes a 1031 exchange: sells Long Beach industrial at $25M gain, defers all taxes into a Phoenix industrial portfolio. 7 years later, sells Phoenix portfolio for $40M gain. Total deferred gain now:', opts: ['$25M only from original exchange', '$25M original + $40M new gain = $65M total deferred (assuming another 1031), or $65M taxable if sold outright', '$40M new gain only', '$0 — after 7 years, original gain expires'], a: 1, exp: 'Each successive 1031 carries forward accumulated deferred gains plus new appreciation. After two deferred exchanges with $25M + $40M = $65M total deferred gain, a final sale without 1031 triggers $65M in recognized gain. The longer you defer, the larger the eventual tax bill — but the longer your capital compounds tax-free.' },
      { q: 'An investor needs to close on a $20M replacement property within the 180-day exchange window. The original sale closed January 15. The replacement must close by:', opts: ['June 15', 'July 14', 'July 15', 'February 15'], a: 1, exp: 'January 15 + 180 days = July 14. Note: 45-day ID deadline is March 1 (Jan 15 + 45 days).' },
      { q: 'In a high-interest rate environment, why might a cash-out refinance be preferred over a 1031 exchange?', opts: ['Refinancing avoids all state taxes', '1031 requires buying a replacement — if good replacement deals are scarce or overpriced, a refinance extracts equity tax-free without forcing deployment into a mediocre deal', 'Refinancing has no closing costs', 'The 180-day deadline is waived in high-rate environments'], a: 1, exp: 'A 1031 forces you to deploy into a replacement property. In markets where good deals are hard to find (high prices, limited inventory), a refinance lets you extract equity without the reinvestment obligation — avoiding a forced "bad 1031" into an overpriced deal.' },
      { q: 'Which of these parties does NOT need to be involved in a valid California 1031 exchange?', opts: ['Qualified Intermediary (QI)', 'Both closing agents (relinquished and replacement escrow companies)', 'The California Board of Equalization', 'Title insurance companies for both properties'], a: 2, exp: 'The California Board of Equalization handles sales tax — not relevant to 1031 exchanges. A valid CA 1031 requires: QI, closing agents on both ends, and title companies. The IRS and state FTB require proper reporting, but no state agency must be "involved" in the transaction mechanics.' },
    ],
  },
  11: {
    sessions: [
      { day: 'Mon Apr 13', title: 'Session 1 — Vocabulary: Investment Thesis, Market Overview, Underwriting Assumptions, IC' },
      { day: 'Wed Apr 15', title: 'Session 2 — Investment Memo Structure: From Thesis to Risk to Recommendation' },
      { day: 'Thu Apr 16', title: 'Session 3 — Sensitivity Analysis in an IC Memo: What the Committee Wants to See' },
      { day: 'Fri Apr 17', title: 'Session 4 — Writing a Go/No-Go Recommendation + 20-Question Quiz' },
    ],
    vocabulary: [
      { term: 'Investment Thesis', full: 'Investment Thesis', definition: 'The core argument for why a specific investment will generate target returns. Connects market fundamentals (demand drivers, vacancy, rent growth), asset-specific opportunity (value-add, location, basis), and execution strategy. Must be specific, differentiated, and supported by data — not just "SoCal industrial is good."', example: '"Port-proximate Long Beach industrial with 18-month lease expiration at 74% of market rent; acquire below replacement cost; mark-to-market at expiration; exit at market cap. Basis: $185/SF vs. $260/SF replacement cost."' },
      { term: 'Market Overview', full: 'Market Overview Section', definition: 'The market analysis section of an investment memo documenting the macro and submarket context: vacancy, absorption, rent growth, supply pipeline, and demand drivers. Provides the evidence base for rent growth and exit cap rate assumptions in the underwriting.', example: 'Long Beach industrial submarket: 2.8% vacancy; +2.1M SF absorption YTD; $1.95/SF/mo avg asking rent (up 6% YoY); 800K SF pipeline (0.8% of inventory). Supports 3.0% annual rent growth assumption.' },
      { term: 'Underwriting Assumptions', full: 'Underwriting Assumptions', definition: 'The specific numerical inputs in the financial model: going-in NOI, rent growth rate, vacancy/lease-up period, renovation budget, exit cap rate, hold period, financing terms. Each assumption must be supported by market data or deal specifics. The IC will challenge every assumption — know your support.', example: 'Assumptions: going-in NOI $920K; 3.0% annual rent growth; 9-month lease-up at 55% occupancy; $12/SF renovation; 5.0% exit cap; 5-year hold; 65% LTV bridge loan at SOFR+275.' },
      { term: 'Sensitivity Analysis', full: 'Sensitivity Analysis (Investment Memo)', definition: 'A table showing how returns (IRR, equity multiple) change under different assumptions for key inputs. The IC will stress exit cap rate (most sensitive) and rent growth. A well-presented sensitivity table shows base, upside, and downside scenarios with labeled assumptions — demonstrating that the deal still works under reasonable stress.', example: 'Sensitivity table: rows = exit cap (4.75%, 5.00%, 5.25%, 5.50%); columns = rent growth (2%, 3%, 4%). Base = 5.00% / 3.0% = 16.2% IRR. Stress = 5.50% / 2.0% = 12.8% IRR.' },
      { term: 'Risk Mitigants', full: 'Risk and Mitigant Analysis', definition: 'A section of the investment memo that identifies the top 3–5 risks to the investment thesis and pairs each with a specific mitigating factor. Demonstrates intellectual honesty and analytical rigor — an IC that sees risks you haven\'t identified will lose confidence in your memo.', example: 'Risk: tenant does not renew at lease expiration. Mitigant: signed LOI from replacement tenant at market rate; deep broker relationships in Long Beach industrial submarket.' },
      { term: 'Investment Committee', full: 'Investment Committee (IC)', definition: 'The decision-making body that approves or rejects investment proposals. Composed of senior principals (often the GP\'s partners or key LP representatives). Evaluates the memo, challenges assumptions, tests stress scenarios, and votes on go/no-go. IC approval required before committing capital.', example: 'Infinity Capital IC: Peter Parada + Tom HTA + LP representative. IC meeting: 60-minute presentation, 30-minute Q&A, vote on go/no-go, approved/rejected with conditions.' },
    ],
    quiz: [
      { q: 'An investment thesis must be:', opts: ['Optimistic about all market conditions', 'Specific, data-supported, and differentiated — connecting market conditions to asset-specific opportunity and execution strategy', 'Written by an outside broker', 'Approved by the tenants before IC presentation'], a: 1, exp: 'A strong thesis tells the IC: (1) why this market/submarket, (2) why this asset specifically, (3) what we will do to create value, (4) why we will succeed. Generic statements ("SoCal is a great market") without specific asset analysis are not investment theses.' },
      { q: 'The market overview section of an investment memo is used to:', opts: ['Describe the property\'s physical characteristics', 'Support the rent growth and exit cap rate assumptions with data-driven market context', 'List the broker contacts in the market', 'Calculate the going-in cap rate'], a: 1, exp: 'Market overview evidence-bases the model. If you assume 3% rent growth, the market section shows why (2.8% vacancy, positive absorption, limited pipeline). IC will ask "why 3%?" — your market section is the answer.' },
      { q: 'The most challenged underwriting assumption in an industrial investment IC presentation is typically:', opts: ['The going-in NOI', 'The exit cap rate — most sensitive input, hardest to predict, largest impact on total return', 'The lease-up timeline', 'The acquisition price'], a: 1, exp: 'Exit cap rate drives reversion value, which is 60–80% of total DCF value. A 50-bps change in exit cap creates a $2M+ swing in a typical deal. IC will always ask: "What if the exit cap is 50 bps higher? Still works?"' },
      { q: 'A sensitivity table in an investment memo should show:', opts: ['Only the best-case scenario to maximize IC enthusiasm', 'Base case, upside, and downside across the 2–3 most sensitive inputs — demonstrating the deal performs acceptably under reasonable stress', 'All possible scenarios (thousands of combinations)', 'Only the downside to be conservative'], a: 1, exp: 'A good sensitivity table shows: (1) base case (management\'s best estimate), (2) upside (optimistic but possible), (3) downside (realistic bad scenario). Shows IC the range of outcomes without hiding risks.' },
      { q: 'A risk/mitigant section strengthens an investment memo by:', opts: ['Admitting the deal might fail', 'Demonstrating the analyst thought critically about what could go wrong AND has specific responses — building IC confidence in the analysis', 'Reducing the target IRR to be conservative', 'Identifying risks so the IC can reject the deal'], a: 1, exp: 'ICs know every deal has risks. Explicitly identifying risks and pairing them with credible mitigants shows intellectual rigor. An analyst who says "no significant risks" loses more credibility than one who says "here are 4 risks and here\'s how we manage them."' },
      { q: 'An investment memo go/no-go recommendation should be:', opts: ['Always "go" — why would you bring a "no-go" to IC?', 'Clear, specific, and conditional if relevant: "recommend acquisition at ≤$XX/SF acquisition price, subject to environmental clearance and lease execution with Tenant A"', 'Vague to avoid commitment', 'Based solely on the broker\'s view'], a: 1, exp: 'A good recommendation is specific: recommends acquisition at a defined price/terms, flags any conditions (diligence items, LOI execution), and clearly states the analyst\'s view. "We recommend proceeding" without conditions is incomplete; "we pass" without rationale is useless.' },
      { q: 'IC will typically ask which question FIRST about a value-add industrial memo?', opts: ['What is the broker\'s commission?', '"What happens to returns if the tenant doesn\'t renew and lease-up takes 18 months instead of 9?" — lease-up risk is the core value-add risk', '"Is the building LEED certified?"', '"What was the seller\'s original purchase price?"'], a: 1, exp: 'IC zeroes in on the biggest risk in any value-add industrial deal: lease-up. Extended vacancy = lost income = lower IRR. The IC wants to see: (1) you\'ve stress-tested it, (2) the deal still works at extended lease-up, (3) you have a plan for re-tenanting.' },
      { q: 'An investment memo\'s market section shows 2.8% industrial vacancy and 3% asking rent growth YoY. The model assumes 4% annual rent growth for 10 years. The IC will likely say:', opts: ['Approved — 4% is conservative vs. market', 'Challenge the 4% assumption: current growth is 3%, and 4% compounded over 10 years implies above-trend performance. Justify or reduce to 3%.', 'Approved — higher rent growth makes the deal better', 'Pass — any rent growth assumption over 3% is aggressive'], a: 1, exp: 'Model assumptions must align with or be explained vs. market data. 4% model vs. 3% current growth is a 100-bps gap that IC will challenge. Either justify (historical CAGR supports 4%, near-term pipeline is limited) or adjust to 3%.' },
      { q: 'What does a "waterfall sensitivity table" show in a JV investment memo?', opts: ['Cap rate vs. rent growth matrix only', 'How LP and GP returns change at different IRR outcomes — useful for showing LP that they hit their preferred return in base and stress cases', 'The property\'s drainage system', 'Annual cash flow distribution'], a: 1, exp: 'A waterfall sensitivity shows LP and GP economics at various overall deal IRRs: does LP pref get paid even in stress case? At what IRR does GP earn its full promote? Demonstrates to LP that their downside is protected.' },
      { q: 'The investment committee will typically approve a deal if:', opts: ['IRR exceeds the hurdle in the base case only', 'Base case IRR exceeds hurdle, stress case IRR remains acceptable, key risks are identified with credible mitigants, and the analyst can defend every assumption', 'The property is in SoCal', 'The broker recommends it strongly'], a: 1, exp: 'IC approval requires: base case above hurdle, acceptable downside, identified risks with mitigants, and a confident, knowledgeable presenter who can defend the underwriting under scrutiny. Any undefended assumption undermines the entire memo.' },
      { q: 'A Long Beach industrial investment memo has a base case IRR of 16.5% and a stress case (6-month extended lease-up + 50 bps exit cap expansion) of 11.0%. IC target is 14% minimum. You should:', opts: ['Present only the base case', 'Present both cases; acknowledge the stress case misses target; propose strategies to improve stress case (lower acquisition price, pre-leasing, better renovation plan)', 'Adjust the stress case assumptions to hit 14%', 'Pass on the deal immediately'], a: 1, exp: 'Honest presentation builds IC credibility. Identify why stress fails and propose mitigants: negotiate lower price (improves all scenarios), pursue pre-leasing LOI (reduces lease-up risk), or accept that stress at 11% is acceptable risk given the base case upside.' },
      { q: 'When presenting underwriting assumptions, the presenter should be able to answer: "Where did this number come from?"', opts: ['Only for the acquisition price', 'For EVERY assumption — each input should have a market data source, comparable transaction, or deal-specific justification', 'Only for the return metrics', 'Just for the rent growth and exit cap'], a: 1, exp: 'IC trust is built assumption by assumption. "We used 3% rent growth because CBRE\'s 2024 market report shows 3-year CAGR of 3.1% for Long Beach industrial" builds more confidence than "we felt 3% was reasonable." Every number needs a source.' },
      { q: 'Investment memo executive summary should be:', opts: ['2–3 pages detailing all financial calculations', 'Half a page to one page: deal summary, investment thesis, key return metrics, top risks, and recommendation — enough for a busy IC member to understand the deal in 3 minutes', 'The same as the full memo but bolded', 'Written after IC approval'], a: 1, exp: 'Executive summary = decision brief. Senior IC members often read only the exec summary before the meeting. It must stand alone: what is the deal, why do we like it, what do we make, what could go wrong, and do we recommend it.' },
      { q: 'After an IC meeting, an IC member says: "I like the deal but I\'m concerned about lease-up timing. Can you get a letter of intent from a replacement tenant before we commit?" This is:', opts: ['A rejection — don\'t proceed', 'A conditional approval — IC is interested but wants a specific risk mitigant executed before committing capital', 'Standard IC procedure — always get LOIs before any deal', 'A request to rewrite the investment memo'], a: 1, exp: 'Conditional approvals are common: "we\'ll approve subject to [specific condition]." The analyst\'s job is to satisfy the condition (get the LOI) and return to IC for final approval. Not a rejection — a risk mitigation request.' },
      { q: 'Which of these belongs in the "underwriting assumptions" section of an industrial investment memo?', opts: ['The seller\'s asking price history', 'Year 1 NOI, annual rent growth rate, vacancy rate, renovation budget, lease-up period, exit cap rate, and hold period — the specific model inputs with source justification', 'The broker commission agreement', 'The city\'s zoning map for the submarket'], a: 1, exp: 'Underwriting assumptions = the model inputs that the IC will scrutinize. Every key driver of return (NOI, growth, costs, timing, exit) should be stated with its supporting rationale.' },
      { q: 'An investment memo for an Infinity Capital Long Beach industrial deal concludes with "We recommend acquisition at a maximum price of $185/SF ($18.5M for 100K SF), contingent on Phase I environmental clearance and confirmation of the 5-year lease renewal option with Tenant A." This recommendation is:', opts: ['Too conditional — remove the contingencies', 'Well-structured: clear price limit, identified contingencies, and specific conditions that must be met before committing', 'Too aggressive — recommend a lower price', 'Incomplete — needs broker sign-off'], a: 1, exp: 'A specific, conditional recommendation protects the investment: it commits to a maximum price (no bidding war), identifies environmental diligence as gating, and ensures the key lease option is confirmed before capital is at risk.' },
      { q: 'When writing the risk section of an investment memo, which risks should be included?', opts: ['Only risks that are likely to happen', 'The top 3–5 material risks that could cause the deal to underperform, with each paired with a specific mitigant — not every conceivable risk', 'Only risks beyond the investor\'s control', 'Zero risks — stating risks makes the deal look bad'], a: 1, exp: 'Focus on material, deal-specific risks with paired mitigants: lease-up risk, renovation overrun, exit cap expansion, market softening. Include only risks that could materially move returns. Mitigants show how you\'d respond.' },
      { q: 'A sensitivity table shows: at 5.25% exit cap and 3% rent growth = 15.5% IRR; at 5.75% and 2% = 11.5% IRR. IC target IRR = 14%. This tells you:', opts: ['The deal always works', 'The deal hits target at base but misses under stress — the IC needs to decide whether the stress scenario is plausible and whether 11.5% is an acceptable downside', 'The deal always fails', 'The sensitivity table is wrong — results should be higher'], a: 1, exp: 'Sensitivity tables don\'t give yes/no — they show the return range. IC must judge: how likely is the stress scenario (5.75% exit cap, 2% growth)? If plausible, is 11.5% downside acceptable vs. the 15.5% upside? Good IC discussion extracts this judgment.' },
      { q: 'The final slide of an Infinity Capital IC presentation on a Long Beach industrial value-add deal should contain:', opts: ['The full 10-year DCF model in detail', 'A clear summary: deal name, acquisition price, target returns (base and stress), top 2–3 risks with mitigants, and a direct recommendation with conditions', 'The QI agreement for the 1031 exchange', 'The lease comparables spreadsheet'], a: 1, exp: 'Final slide = decision-ready summary. IC members make a vote. Give them: what are we buying, what do we make, what could go wrong, and should we do it? Everything else in the memo is support for this final frame.' },
    ],
  },
  12: {
    sessions: [
      { day: 'Mon Apr 20', title: 'Session 1 — Vocabulary: Deal Presentation, Return Attribution, IC Recommendation, Full-Cycle Analysis' },
      { day: 'Wed Apr 22', title: 'Session 2 — Capstone Prep: Applying Domains 1–4 to a Live Infinity Capital Deal' },
      { day: 'Thu Apr 23', title: 'Session 3 — Capstone Presentation: IC Q&A Simulation with Peter and Tom' },
      { day: 'Fri Apr 24', title: 'Session 4 — Domain 4 Debrief and Full-Program Integration Review' },
    ],
    vocabulary: [
      { term: 'Deal Presentation', full: 'IC Deal Presentation', definition: 'The formal presentation to an investment committee covering the full investment case: market context, asset overview, investment thesis, financial model, return analysis, sensitivity table, risks and mitigants, and go/no-go recommendation. Must be concise, data-driven, and defensible under aggressive questioning.', example: 'A 20-minute IC presentation on a Long Beach industrial acquisition: 5 slides — exec summary, market, underwriting, waterfall, and recommendation.' },
      { term: 'Return Attribution', full: 'Return Attribution Analysis', definition: 'Breaking down total IRR into its component sources: cash flow yield (NOI distributions), NOI growth (rent increases), and appreciation (exit cap rate change). Shows how much of the return comes from income vs. growth vs. capital gain. Helps IC understand return quality and risk.', example: 'Total IRR 16%: 3% from current cash flow, 5% from NOI growth (rent mark-to-market), 8% from appreciation (exit cap compression). Predominantly appreciation-driven — higher risk profile.' },
      { term: 'Full-Cycle Analysis', full: 'Full-Cycle Investment Analysis', definition: 'Evaluating an investment from acquisition through hold period through exit — considering all phases: purchase, renovation/lease-up, stabilization, hold period management, and disposition. Ensures no phase is underweighted in the return analysis. The capstone skill for a complete CRE investment analyst.', example: 'Full-cycle analysis: acquisition at 4.5% cap → renovation → lease-up → stabilization at 6.5% yield on cost → 5-year stabilized hold → exit at 5.0% cap. IRR: 17.5%.' },
      { term: 'IC Recommendation', full: 'Investment Committee Recommendation', definition: 'The analyst\'s clear go/no-go recommendation to the IC with specific conditions and rationale. The single most important sentence in an investment memo: "We recommend acquisition at a maximum price of $X, subject to [conditions], based on [thesis summary]." Requires courage and analytical conviction.', example: '"We recommend proceeding at ≤$19.5M ($195/SF), subject to Phase I clearance and broker confirmation of active tenant relocation demand. Base case IRR: 16.5%; stress case: 12.8%. Risk-adjusted return exceeds IC hurdle."' },
      { term: 'Infinity Capital', full: 'Infinity Capital (HTA Investment Platform)', definition: 'The investment and development arm of HTA Construction & Development, focused on acquiring, developing, and managing commercial real estate in the LA Basin. The builder/developer perspective combined with investment underwriting creates a competitive advantage in evaluating project feasibility, construction cost, and execution risk.', example: 'Infinity Capital acquires a value-add Long Beach industrial building — HTA\'s construction expertise enables accurate renovation budgeting and faster execution vs. pure investment firms without GC capabilities.' },
    ],
    quiz: [
      { q: 'Return attribution analysis for a value-add industrial deal shows 60% of IRR comes from the exit cap compression assumption. This indicates:', opts: ['The deal is very safe', 'The deal is heavily dependent on cap rate movements — a risky assumption; stress-test the exit cap aggressively', 'The analysis is correct and complete', 'The IC should approve immediately'], a: 1, exp: 'High dependence on cap rate compression (exit cap below going-in cap) introduces market risk: if rates don\'t compress or if they expand, the return collapses. A well-structured value-add deal should generate returns primarily from NOI growth, not cap rate bets.' },
      { q: 'In a full-cycle industrial investment analysis, the acquisition phase due diligence should include:', opts: ['Physical inspection only', 'Physical (building condition, environmental), financial (rent roll, operating history), legal (title, leases, entitlements), and market (comp rents, vacancy) diligence — all four dimensions', 'Financial model review only', 'Broker opinion of value only'], a: 1, exp: 'Full-cycle begins at acquisition diligence. Miss a physical (unknown deferred maintenance), financial (overstated NOI), legal (easement), or market (overestimated market rent) issue and every subsequent phase is compromised.' },
      { q: 'HTA\'s construction expertise gives Infinity Capital what specific competitive advantage in value-add industrial deals?', opts: ['Access to lower-rate financing', 'Accurate renovation budgeting and faster execution — HTA can price construction scope precisely, avoid surprises, and self-perform some work faster than pure investors who must outsource all renovation management', 'Better broker relationships', 'Higher leverage capacity'], a: 1, exp: 'GP with in-house GC = lower renovation cost uncertainty and execution risk. A pure investor bids renovation work out and relies on a third-party GC. HTA/Infinity Capital knows their renovation costs from day-one underwriting and can execute the business plan with direct control.' },
      { q: 'A full-cycle analysis integrating all Domain 4 concepts requires which combination of skills?', opts: ['Cap rates and comp analysis only', 'Cap rates + asset class analysis + comp valuation + DCF modeling + debt structuring + market dynamics + value-add underwriting + JV waterfall + asset management + disposition strategy', 'DCF and JV waterfall only', 'Market report reading only'], a: 1, exp: 'Full-cycle = all Domain 4 skills integrated: market drives assumptions, asset class determines strategy, comps validate pricing, DCF models cash flows, debt structures leverage, market data supports rent growth, value-add business plan drives execution, waterfall determines LP/GP economics, asset management holds the plan, and 1031/disposition optimizes exit.' },
      { q: 'The Infinity Capital capstone deal IC recommendation requires a clear go/no-go. What makes a "no-go" recommendation credible and respected?', opts: ['Saying no is always the safest choice', 'A no-go recommendation with specific, data-supported rationale (e.g., "basis too high relative to comps, stress case fails IC hurdle, lease-up risk too concentrated") demonstrates analytical rigor — IC respects disciplined analysts who will say no when the deal doesn\'t work', 'Never recommend no-go — it wastes IC\'s time', 'Say no-go only for legal problems'], a: 1, exp: 'Disciplined analysts who decline deals when the numbers don\'t work build more IC trust than analysts who always find a way to make the deal work. A no-go recommendation with clear rationale demonstrates the analysis is rigorous, not salesmanship.' },
      { q: 'Domain 4 Week 12 capstone tests ability to integrate which financial skills?', opts: ['Only cap rate calculations', 'Cap rate mechanics → asset class analysis → comp valuation → 10-year DCF → debt structuring → market narrative → value-add underwriting → JV waterfall → asset management → disposition strategy — all integrated into a single, IC-ready investment memo', 'JV waterfall only', 'Market report reading only'], a: 1, exp: 'The capstone demonstrates full integration: no single week\'s skill stands alone. A real deal requires all skills simultaneously: what is the market context (W1, W2, W6), what is the asset worth (W3), what do we model (W4), how do we finance it (W5), what value-add strategy (W7), how does JV work (W8), how do we manage it (W9), and how do we exit (W10) — presented as an investment memo (W11).' },
      { q: 'Return attribution showing 4% IRR from cash flow, 6% from rent/NOI growth, and 7% from appreciation = 17% total IRR. What is the "quality" assessment of this return?', opts: ['Low quality — too dependent on appreciation', 'Balanced — roughly 1/3 each from cash flow, growth, and appreciation. The appreciation component should be stress-tested, but the deal doesn\'t rely solely on cap rate compression.', 'High quality — appreciation-driven returns are always superior', 'Cannot assess quality from return attribution alone'], a: 1, exp: 'A balanced attribution (income + growth + appreciation) is healthier than appreciation-only. If 14 of 17% comes from appreciation, the deal fails completely if cap rates don\'t move. A 1/3-each split means the deal generates real cash and NOI growth even if appreciation disappoints.' },
      { q: 'HTA/Infinity Capital is evaluating a Long Beach industrial deal. Construction estimates renovation at $8/SF vs. a competing investor\'s $15/SF estimate. This cost advantage could enable HTA to:', opts: ['Bid more aggressively (higher acquisition price) while still hitting return targets', 'Acquire at a lower price than competitors while matching their return targets, or bid slightly higher and still outperform competitors on returns', 'Guarantee a faster lease-up', 'Reduce the exit cap rate assumption'], a: 1, exp: 'HTA\'s $7/SF renovation savings on a 100K SF building = $700K cost advantage. At a 5% exit cap, that $700K of additional NOI capacity = $14M of value-creation differential. This genuine cost advantage can be monetized through higher bid prices (competitive advantage) or retained as superior returns (LP advantage).' },
      { q: 'At the IC presentation for the Domain 4 capstone, Peter asks: "What\'s your biggest single risk to this deal?" The correct response is:', opts: ['There are no material risks', 'Identify the specific, deal-critical risk with highest probability of occurring (e.g., lease-up extends to 15 months), explain its financial impact on IRR, and describe your mitigation strategy', 'Cap rate expansion in general', 'Interest rate risk'], a: 1, exp: 'IC expects specific, deal-aware risk identification. Generic answers ("interest rates could rise") show shallow analysis. Specific answers ("if lease-up extends to 15 months from our 9-month base case, IRR drops from 16% to 12% — here\'s how we mitigate: active pre-leasing campaign starting at acquisition") demonstrate mastery.' },
      { q: 'Full-cycle return for a 5-year value-add industrial deal: buy at $16M, invest $1.5M renovation, exit at $23M. Total profit before equity multiple calculation:', opts: ['$5.5M', '$7M', '$23M', '$1.5M'], a: 0, exp: 'Total invested: $16M + $1.5M = $17.5M. Exit: $23M. Profit: $23M − $17.5M = $5.5M (before financing costs and time value).' },
      { q: 'A well-structured Domain 4 capstone investment memo is approximately:', opts: ['50 pages with all financial calculations', '8–12 pages: exec summary, market overview, asset description, investment thesis, financial model summary, waterfall, sensitivity, risks, and recommendation — concise enough for busy IC, complete enough to defend', 'One page only', '25 slides minimum'], a: 1, exp: 'IC memos balance completeness with concision. 8–12 pages with clear sections allows thorough IC review without overwhelming. Supporting detail (full DCF, comp grid, market data) goes in appendices. The main body is the decision document; appendices are the evidence.' },
      { q: 'Domain 4 builds on Domain 1 (Real Estate Development) primarily because:', opts: ['Domain 1 and 4 are completely independent', 'Domain 1 covers pro forma, capital stack, and YOC mechanics — Domain 4 extends these into full investment analysis: DCF, JV structuring, market analysis, and disposition — using the same fundamental income approach but adding the full investment lifecycle', 'Domain 4 only applies to multifamily, Domain 1 to industrial', 'Domain 1 is for building; Domain 4 is for selling'], a: 1, exp: 'Domain 1 builds the foundation: NOI, cap rate, LTV, DSCR, capital stack, entitlement. Domain 4 extends this into a complete investment platform: DCF, IRR, JV waterfall, market analysis, value-add strategy, asset management, and disposition optimization.' },
      { q: 'An IC member challenges: "Your 3% rent growth assumption seems high given the supply pipeline." The correct response is:', opts: ['Agree and reduce to 1% immediately', 'Defend with data: "The pipeline of 1.2M SF delivers over 18 months against 2.1M SF of annual absorption — net demand still exceeds supply. Historical 10-year CAGR for this submarket is 3.2%. We believe 3% is supported." Then offer to show the stress case at 2%.', 'Disagree and hold your position', 'Remove rent growth from the model entirely'], a: 1, exp: 'Defending assumptions under pressure is a key IC skill. Lead with data (historical CAGR, pipeline vs. absorption), acknowledge the concern, then offer the stress case. Shows you anticipated the question and prepared the answer.' },
      { q: 'Return attribution: deal A has 80% of returns from NOI growth; deal B has 80% from exit cap compression. In a rising rate environment, which deal has lower risk?', opts: ['Deal B — cap rate compression is more certain', 'Deal A — returns driven by NOI growth (actual income increases) are less dependent on market conditions than cap rate movements', 'Equal risk', 'Cannot determine without more information'], a: 1, exp: 'In a rising rate environment, cap rate compression is unlikely (cap rates tend to follow rates up). Deal A\'s NOI-growth-driven returns are achievable even if rates rise. Deal B relies on cap rates falling — directly opposed to the rising rate environment thesis.' },
      { q: 'Completing Domain 4 means the student can perform all of the following EXCEPT:', opts: ['Underwrite a 10-year DCF and calculate IRR', 'Build and execute a 1031 exchange from scratch without a QI', 'Present an investment memo to an IC', 'Structure a JV waterfall and calculate GP promote'], a: 1, exp: '1031 exchanges must be managed by a licensed QI — the investor does not execute independently. Domain 4 teaches you to understand, plan, and optimize a 1031 strategy. The actual execution requires a licensed QI (not a skill HTA does alone).' },
      { q: 'The HTA Builder Academy program integrates all 4 domains. Which correctly describes how they connect?', opts: ['They are independent — each domain can be used without the others', 'Domain 1 (development) builds the foundation; Domain 2 (construction) provides execution knowledge; Domain 3 (contracts) governs the legal framework; Domain 4 (investment) integrates them all into full-cycle investment analysis — a development project, constructed by HTA, documented in contracts, underwritten as a deal', 'Domain 4 is the only domain that matters for real estate careers', 'Domain 3 (contracts) is the most important for investment analysis'], a: 1, exp: 'The four domains reflect HTA\'s complete platform: develop it (D1), build it (D2), contract it (D3), invest in it (D4). A student who completes all four can originate, underwrite, execute, and exit a commercial real estate deal from end-to-end — the complete HTA/Infinity Capital skillset.' },
      { q: 'After completing the full HTA Builder Academy program, what single skill best demonstrates mastery?', opts: ['Memorizing cap rate benchmarks', 'Presenting a defensible, data-supported go/no-go recommendation on a real deal to experienced principals, fielding challenging questions, and adjusting the analysis when new information arises — applied judgment, not just knowledge', 'Building a perfect Excel DCF model', 'Knowing all AIA contract articles by number'], a: 1, exp: 'Mastery = applied judgment under pressure. Knowing concepts is table stakes. The capstone test is: can you take a real deal, apply all four domains of knowledge, form an independent view, defend it to experienced principals who will challenge every assumption, and make a sound decision? That\'s the HTA Builder Academy goal.' },
    ],
  },
}
